import { TemplateParser } from './TemplateParser';
import { TypeGenerator } from './TypeGenerator';
import { LatexRenderer } from './LatexRenderer';
import { PdfGenerator } from './PdfGenerator';
import path from 'path';
import fs from 'fs';
import { StdioOptions } from 'child_process';

// Define ReportType as a union of string literals
const REPORT_MAP_FILE = path.join(__dirname, 'reportTypeMap.json');

export class LatexToPdf {
  private templatePath: string;
  private static reportTypeToPathMap: Record<string, string> | null = null;

  constructor(reportType: string) {
    if (!LatexToPdf.reportTypeToPathMap) {
      LatexToPdf.loadReportTypeMap();
    }

    const templatePath = LatexToPdf.reportTypeToPathMap?.[reportType];

    if (!templatePath) {
      throw new Error(`Template path not found for report type: ${reportType}\nValid types: ${Object.keys(LatexToPdf.reportTypeToPathMap || {}).join(', ')}`);
    }

    this.templatePath = templatePath;
    let parsed=TemplateParser.extractFields(this.templatePath);
    //let interfaceName = TypeGenerator.writeInterface(templatePath,parsed);
    //console.log(`Generated TypeScript interface: ${interfaceName}`);
  }

  populate<T>(data: T, output: string,stdioOption:StdioOptions='ignore'): string {
    
    const populatedTex = LatexRenderer.populateTemplate(this.templatePath, data as any, output);
    return PdfGenerator.generatePdf(populatedTex, output,stdioOption);
  }

  private static loadReportTypeMap() {
    if (fs.existsSync(REPORT_MAP_FILE)) {
      LatexToPdf.reportTypeToPathMap = JSON.parse(fs.readFileSync(REPORT_MAP_FILE, 'utf-8'));
    } else {
      throw new Error("Report type mapping file not found. Run `generateAllTypes` first.");
    }
  }
}

export function generateAllTypes(templateDir: string): string[] {
  const templateFiles = fs.readdirSync(templateDir).filter(file => file.endsWith('.tex')||file.endsWith('.tytex'));

  const reportTypeToPathMap: Record<string, string> = {};

  const reportTypes = templateFiles.map(templateFile => {
    const reportName = path.basename(templateFile, '.tex').replace(/-/g, '_');
    const templatePath = path.join(templateDir, templateFile);
    
    reportTypeToPathMap[reportName] = templatePath;
    let parsed=TemplateParser.extractFields(templatePath);
    let interfaceName = TypeGenerator.writeInterface(templatePath,parsed);
    
    return reportName;
  });

  // Write the mapping to a JSON file
  fs.writeFileSync(REPORT_MAP_FILE, JSON.stringify(reportTypeToPathMap, null, 2));

  return reportTypes;
}

